import React, { useEffect } from 'react';
import { Typography, Card, CardMedia, CardContent, Divider } from '@mui/material';
import { Link, useParams } from 'react-router-dom';
import fetchModel from '../../modelData/models';

const UserPhotos = ({ setContext }) => {
  const { userId } = useParams();
  const photos = fetchModel.photoOfUserModel(userId);
  const user = fetchModel.userModel(userId);

  useEffect(() => {
    if (user) {
      setContext(`Photos of ${user.first_name} ${user.last_name}`);
    }
  }, [user, setContext]);

  if (!photos) return <Typography>Loading photos...</Typography>;

  return (
    <div style={{ padding: '10px' }}>
      {photos.map((photo) => (
        <Card key={photo._id} style={{ marginBottom: '30px' }} elevation={3}>
          {/* Hiển thị ảnh thực tế từ thư mục images */}
          <CardMedia
            component="img"
            style={{ width: '100%', height: 'auto' }}
            image={require(`../../images/${photo.file_name}`)}
            alt="User uploaded"
          />

          <CardContent>
            <Typography variant="caption" color="textSecondary">
              Posted on: {new Date(photo.date_time).toLocaleString()}
            </Typography>

            <Typography variant="h6" style={{ marginTop: '15px' }}>Comments:</Typography>
            <Divider style={{ marginBottom: '10px' }} />

            {photo.comments ? photo.comments.map(comment => (
              <div key={comment._id} style={{ marginBottom: '15px', paddingLeft: '10px', borderLeft: '2px solid #f0f0f0' }}>
                <Typography variant="body2">
                  {/* Link dẫn về trang cá nhân của người bình luận */}
                  <Link to={`/users/${comment.user._id}`} style={{ textDecoration: 'none', color: '#1976d2', fontWeight: 'bold' }}>
                    {comment.user.first_name} {comment.user.last_name}
                  </Link>
                  {": "} 
                  {comment.comment}
                </Typography>
                <Typography variant="caption" color="textSecondary">
                  {new Date(comment.date_time).toLocaleString()}
                </Typography>
              </div>
            )) : (
              <Typography variant="body2" color="textSecondary">No comments yet.</Typography>
            )}
          </CardContent>
        </Card>
      ))}
    </div>
  );
};

export default UserPhotos;
